import{_ as l,I as i,o as a,c as o,a5 as e,b as n,w as s,a as d,J as c,a6 as h,ae as g,af as p}from"./chunks/framework.n-NEOxdA.js";const k=JSON.parse('{"title":"歌单","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"playlist.md","filePath":"playlist.md"}'),b={name:"playlist.md"};function E(A,t,_,u,m,y){const r=i("Mermaid");return a(),o("div",null,[t[1]||(t[1]=e('<h1 id="歌单" tabindex="-1">歌单 <a class="header-anchor" href="#歌单" aria-label="Permalink to “歌单”">​</a></h1><p>相关文档：<a href="/music-free-site/music.html">音乐管理</a> · <a href="/music-free-site/plugin-collection.html">插件合集</a> · <a href="/music-free-site/user.html">用户</a> · <a href="/music-free-site/opensubsonic-api.html">OpenSubsonic API</a></p><p><img src="'+g+'" alt=""></p><h2 id="_1-模块概述" tabindex="-1">1. 模块概述 <a class="header-anchor" href="#_1-模块概述" aria-label="Permalink to “1. 模块概述”">​</a></h2><p><strong>歌单模块</strong>用于创建、浏览与管理用户歌单，并支持从外部平台（网易云、QQ 音乐等）<strong>按链接导入</strong>歌单、与本地曲库<strong>匹配</strong>后播放。核心入口：</p><table tabindex="0"><thead><tr><th>入口</th><th>路径</th><th>侧栏名称</th></tr></thead><tbody><tr><td>歌单列表</td><td><code>/playlists</code></td><td>歌单</td></tr><tr><td>歌单详情</td><td><code>/playlists/:id</code></td><td>（从列表进入）</td></tr></tbody></table>',6)),(a(),n(h,null,{default:s(()=>[c(r,{id:"mermaid-54",class:"mermaid",graph:"flowchart%20TB%0A%20%20subgraph%20ui%20%5BWeb%20%E5%89%8D%E7%AB%AF%5D%0A%20%20%20%20L%5B%E6%AD%8C%E5%8D%95%E5%88%97%E8%A1%A8%5D%0A%20%20%20%20D%5B%E6%AD%8C%E5%8D%95%E8%AF%A6%E6%83%85%5D%0A%20%20%20%20I%5B%E5%AF%BC%E5%85%A5%E6%AD%8C%E5%8D%95%E5%AF%B9%E8%AF%9D%E6%A1%86%5D%0A%20%20end%0A%20%20subgraph%20local%20%5B%E6%9C%AC%E5%9C%B0%E6%AD%8C%E5%8D%95%5D%0A%20%20%20%20C%5B%E6%96%B0%E5%BB%BA%E7%A9%BA%E6%AD%8C%E5%8D%95%5D%0A%20%20%20%20A%5B%E6%90%9C%E7%B4%A2%E6%B7%BB%E5%8A%A0%E6%9B%B2%E7%9B%AE%5D%0A%20%20end%0A%20%20subgraph%20external%20%5B%E5%A4%96%E9%83%A8%E6%AD%8C%E5%8D%95%5D%0A%20%20%20%20P%5BFetchPlaylist%20%E6%8F%92%E4%BB%B6%5D%0A%20%20%20%20M%5B%E6%9B%B2%E5%BA%93%E6%A8%A1%E7%B3%8A%E5%8C%B9%E9%85%8D%5D%0A%20%20%20%20S%5B%E6%89%8B%E5%8A%A8%2F%E5%AE%9A%E6%97%B6%E5%90%8C%E6%AD%A5%5D%0A%20%20end%0A%20%20subgraph%20play%20%5B%E6%92%AD%E6%94%BE%5D%0A%20%20%20%20Q%5B%E6%92%AD%E6%94%BE%E5%99%A8%E9%98%9F%E5%88%97%5D%0A%20%20end%0A%20%20L%20--%3E%20C%0A%20%20L%20--%3E%20I%0A%20%20I%20--%3E%20P%0A%20%20P%20--%3E%20M%0A%20%20M%20--%3E%20D%0A%20%20C%20--%3E%20A%20--%3E%20D%0A%20%20D%20--%3E%20S%0A%20%20D%20--%3E%20Q%0A"})]),fallback:s(()=>[...t[0]||(t[0]=[d(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e('<p>歌单数据按 <strong>用户</strong> 隔离；可将歌单设为 <strong>公开</strong>，供同服务器其他用户浏览（不可编辑他人歌单）</p><h2 id="_2-访问与权限" tabindex="-1">2. 访问与权限 <a class="header-anchor" href="#_2-访问与权限" aria-label="Permalink to “2. 访问与权限”">​</a></h2><ul><li><strong>入口</strong>：登录后访问 <code>/playlists</code>。</li><li><strong>可见范围</strong>：列表包含 <strong>本人歌单</strong> + <strong>他人公开歌单</strong>（<code>isPublic: true</code>）。</li><li><strong>编辑权限</strong>（<code>canEdit</code>）：仅歌单 <strong>所有者</strong> 可改名、删歌单、增删曲目、同步、切换公开状态；导入的外部歌单对所有者只读曲目列表（见下文）。</li><li><strong>OpenSubsonic</strong>：客户端通过 <code>getPlaylists</code> / <code>getPlaylist</code> 访问同一套数据；管理员可用 <code>username</code> 参数查询指定用户的歌单列表。</li></ul><h2 id="_3-歌单类型" tabindex="-1">3. 歌单类型 <a class="header-anchor" href="#_3-歌单类型" aria-label="Permalink to “3. 歌单类型”">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>曲目来源</th><th>手动增删曲</th></tr></thead><tbody><tr><td><strong>自建歌单</strong></td><td>用户在详情页搜索曲库添加</td><td>支持</td></tr><tr><td><strong>导入歌单</strong></td><td>插件拉取平台列表后与本地匹配</td><td><strong>不支持</strong>（只读；用「同步」更新）</td></tr><tr><td><strong>系统歌单</strong>（预留）</td><td>如每日推荐（规划能力，数据模型已预留）</td><td>由系统维护</td></tr></tbody></table><p>列表卡片上会显示来源平台图标/名称，以及 <strong>「自动同步」</strong> 徽章（<code>syncEnabled: true</code> 时）。</p><h2 id="_4-歌单列表-playlists" tabindex="-1">4. 歌单列表（/playlists） <a class="header-anchor" href="#_4-歌单列表-playlists" aria-label="Permalink to “4. 歌单列表（/playlists）”">​</a></h2><h3 id="_4-1-能做什么" tabindex="-1">4.1 能做什么 <a class="header-anchor" href="#_4-1-能做什么" aria-label="Permalink to “4.1 能做什么”">​</a></h3><ul><li>查看全部可见歌单：封面、名称、曲目数、总时长、公开/来源/自动同步标签。</li><li><strong>新建歌单</strong>：输入名称即可创建空歌单。</li><li><strong>导入歌单</strong>：打开导入对话框，选择插件、粘贴平台歌单链接，可选自定义名称与是否开启自动同步。</li><li><strong>同步</strong>（仅导入歌单且可编辑）：从来源平台重新拉取曲目并刷新匹配结果。</li><li><strong>删除</strong>（仅可编辑歌单）：删除歌单及其条目（不删除本地音频文件）。</li></ul><h3 id="_4-2-导入歌单流程" tabindex="-1">4.2 导入歌单流程 <a class="header-anchor" href="#_4-2-导入歌单流程" aria-label="Permalink to “4.2 导入歌单流程”">​</a></h3><ol><li>点击 <strong>导入歌单</strong>。</li><li>选择实现了 <strong><code>FetchPlaylist</code></strong> 的已启用插件（界面自动筛选）。</li><li>粘贴歌单分享链接（如网易云 <code>https://music.163.com/#/playlist?id=...</code>）。</li><li>可选填写本地显示名称；勾选 <strong>启用自动同步</strong> 后，服务器约每 <strong>6 小时</strong> 自动重新同步该歌单。</li><li>导入完成后展示摘要：<strong>总数 / 已匹配 / 未匹配</strong>；未匹配曲目会列出标题、艺术家与原因。</li></ol><h2 id="_5-歌单详情-playlists-id" tabindex="-1">5. 歌单详情（/playlists/:id） <a class="header-anchor" href="#_5-歌单详情-playlists-id" aria-label="Permalink to “5. 歌单详情（/playlists/:id）”">​</a></h2><p><img src="'+p+`" alt=""></p><h3 id="_5-1-头部信息" tabindex="-1">5.1 头部信息 <a class="header-anchor" href="#_5-1-头部信息" aria-label="Permalink to “5.1 头部信息”">​</a></h3><ul><li>封面、名称、曲目数、总时长、备注（<code>comment</code>）。</li><li>来源平台标识（如「网易云音乐」）。</li><li><strong>公开 / 私有</strong> 开关（仅所有者可改）。</li><li><strong>播放全部</strong>：将歌单中 <strong>可播放</strong> 条目依次加入播放器队列并开始播放。</li><li><strong>同步</strong>（导入歌单）：重新执行平台拉取与本地匹配，并提示匹配统计。</li></ul><h3 id="_5-2-曲目列表" tabindex="-1">5.2 曲目列表 <a class="header-anchor" href="#_5-2-曲目列表" aria-label="Permalink to “5.2 曲目列表”">​</a></h3><p>每条记录包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>序号</td><td>歌单内顺序（<code>position</code>）</td></tr><tr><td>标题 / 艺术家 / 专辑</td><td>展示用元数据</td></tr><tr><td>可播放状态</td><td>✓ 已匹配本地曲库；✗ 未匹配（显示原因）</td></tr><tr><td>时长</td><td>匹配条目用 <code>songs.duration</code>，未匹配用外部时长</td></tr></tbody></table><p><strong>播放规则</strong>：</p><ul><li>仅 <code>playable: true</code> 且存在 <code>songId</code> 的条目可点击播放。</li><li>未匹配条目仍保留在列表中，便于对照补库；悬停/提示可查看 <code>unavailableReason</code>（如未在本地找到）。</li></ul><p><strong>管理操作</strong>（仅 <strong>自建歌单</strong> 且可编辑）：</p><ul><li><strong>+ 添加歌曲</strong>：搜索曲库，多选后加入歌单末尾。</li><li><strong>移除</strong>：从歌单删除已匹配的本地曲目（不删磁盘文件）。</li></ul><p>导入歌单若尝试手动添加/移除，接口会返回只读错误，提示使用同步功能。</p><h2 id="_6-平台同步与本地匹配" tabindex="-1">6. 平台同步与本地匹配 <a class="header-anchor" href="#_6-平台同步与本地匹配" aria-label="Permalink to “6. 平台同步与本地匹配”">​</a></h2><h3 id="_6-1-匹配逻辑" tabindex="-1">6.1 匹配逻辑 <a class="header-anchor" href="#_6-1-匹配逻辑" aria-label="Permalink to “6.1 匹配逻辑”">​</a></h3><p>导入或同步时，对平台返回的每一首曲目：</p><ol><li>在本地 <code>songs</code> 表中按 <strong>标题 + 艺术家</strong>（归一化后精确匹配）查找。</li><li><strong>匹配成功</strong>：写入 <code>playlist_songs</code>，关联 <code>song_id</code>，<code>playable: true</code>。</li><li><strong>匹配失败</strong>：仍写入一条 <strong>占位条目</strong>，保存外部标题/艺术家/专辑/时长与 <code>external_song_id</code>，<code>playable: false</code>。</li></ol><p>同步会 <strong>先清空</strong> 该歌单下旧条目，再按平台最新曲目列表重建（顺序与平台一致）。</p><h3 id="_6-2-手动同步-vs-自动同步" tabindex="-1">6.2 手动同步 vs 自动同步 <a class="header-anchor" href="#_6-2-手动同步-vs-自动同步" aria-label="Permalink to “6.2 手动同步 vs 自动同步”">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>触发</th></tr></thead><tbody><tr><td>手动</td><td>列表或详情页点击 <strong>同步</strong></td></tr><tr><td>自动</td><td>创建/导入时勾选「启用自动同步」；服务端定时任务默认 <strong>每 6 小时</strong> 扫描 <code>sync_enabled=true</code> 的歌单</td></tr></tbody></table><p>同一歌单同步进行中会加锁，避免并发重复请求；同一用户、插件、URL 的重复导入有短冷却（约 10 秒）。</p><h3 id="_6-3-提高匹配率" tabindex="-1">6.3 提高匹配率 <a class="header-anchor" href="#_6-3-提高匹配率" aria-label="Permalink to “6.3 提高匹配率”">​</a></h3><p>未匹配曲目通常因本地曲库缺少对应文件或标签不一致。可：</p><ul><li>在 <strong><a href="/music-free-site/music.html">音乐管理</a></strong> 搜索下载缺失歌曲后再次同步；</li><li>修正本地曲目的标题/艺术家标签后重新同步；</li><li>使用 <strong><a href="/music-free-site/music.html">音乐刮削</a></strong> 统一元数据。</li></ul><h2 id="_7-公开歌单与多用户" tabindex="-1">7. 公开歌单与多用户 <a class="header-anchor" href="#_7-公开歌单与多用户" aria-label="Permalink to “7. 公开歌单与多用户”">​</a></h2><ul><li>自建歌单默认 <strong>私有</strong>；所有者可切换为 <strong>公开</strong>，其他登录用户可在列表中看到并打开详情。</li><li>他人公开歌单 <strong>不可编辑</strong>、不可同步、不可删除。</li><li>OpenSubsonic <code>getPlaylists</code> 返回 <code>public</code>、<code>owner</code> 等字段；<code>getPlaylist</code> 对无权限的私有歌单返回权限错误。</li></ul><h2 id="_8-opensubsonic-与第三方客户端" tabindex="-1">8. OpenSubsonic 与第三方客户端 <a class="header-anchor" href="#_8-opensubsonic-与第三方客户端" aria-label="Permalink to “8. OpenSubsonic 与第三方客户端”">​</a></h2><table tabindex="0"><thead><tr><th>接口</th><th>用途</th></tr></thead><tbody><tr><td><code>getPlaylists</code></td><td>当前用户（或管理员指定 <code>username</code>）可见歌单列表</td></tr><tr><td><code>getPlaylist</code></td><td>歌单详情 + <code>entry</code> 曲目（含未匹配占位 stub）</td></tr><tr><td><code>getCoverArt</code></td><td><code>id=pl-{playlistId}</code> 歌单封面</td></tr></tbody></table><p>Navidrome 兼容 REST（实验性）：</p><ul><li><code>GET /api/playlist</code> — 列表</li><li><code>GET /api/playlist/:id/tracks</code> — 仅 <strong>可播放</strong> 曲目（用于 Navidrome UI）</li><li><code>DELETE /api/playlist/:id</code> — 删除</li></ul><h2 id="_9-典型工作流" tabindex="-1">9. 典型工作流 <a class="header-anchor" href="#_9-典型工作流" aria-label="Permalink to “9. 典型工作流”">​</a></h2><h3 id="_9-1-自建精选歌单" tabindex="-1">9.1 自建精选歌单 <a class="header-anchor" href="#_9-1-自建精选歌单" aria-label="Permalink to “9.1 自建精选歌单”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/playlists → 新建歌单</span></span>
<span class="line"><span>    → 进入详情 → 「+ 添加歌曲」搜索曲库</span></span>
<span class="line"><span>    → 播放全部或单曲播放</span></span></code></pre></div><h3 id="_9-2-从网易云导入并定期更新" tabindex="-1">9.2 从网易云导入并定期更新 <a class="header-anchor" href="#_9-2-从网易云导入并定期更新" aria-label="Permalink to “9.2 从网易云导入并定期更新”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>启用 mf-plugin-netease</span></span>
<span class="line"><span>    → 导入歌单 → 粘贴链接 → 勾选自动同步</span></span>
<span class="line"><span>    → 查看未匹配列表 → 补库后再次「同步」</span></span></code></pre></div><h3 id="_9-3-客户端使用同一歌单" tabindex="-1">9.3 客户端使用同一歌单 <a class="header-anchor" href="#_9-3-客户端使用同一歌单" aria-label="Permalink to “9.3 客户端使用同一歌单”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Feishin 等连接 OpenSubsonic</span></span>
<span class="line"><span>    → getPlaylists / getPlaylist</span></span>
<span class="line"><span>    → 仅可播放条目可 stream；未匹配条目以 stub 形式出现（依客户端实现）</span></span></code></pre></div><hr><h2 id="_10-常见问题" tabindex="-1">10. 常见问题 <a class="header-anchor" href="#_10-常见问题" aria-label="Permalink to “10. 常见问题”">​</a></h2><p><strong>Q：导入后很多歌不能播放？</strong><br> A：这些多为 <strong>未匹配</strong> 条目，本地没有对应音频。补全曲库或修正标签后执行 <strong>同步</strong>。</p><p><strong>Q：为什么不能从导入歌单里删歌或加歌？</strong><br> A：导入歌单以平台为准，曲目列表 <strong>只读</strong>；请在原平台改歌单后在本站 <strong>同步</strong>，或改用自建歌单手动维护。</p><p><strong>Q：自动同步多久一次？</strong><br> A：服务端默认 <strong>每 6 小时</strong> 处理所有 <code>syncEnabled</code> 的歌单；也可随时手动点同步。</p><p><strong>Q：公开歌单别人能改吗？</strong><br> A：不能。仅所有者可编辑与同步。</p><p><strong>Q：和音乐/专辑模块如何配合？</strong><br> A：歌单只引用已有 <code>songs</code>，不直接操作文件。</p>`,54))])}const B=l(b,[["render",E]]);export{k as __pageData,B as default};
